  "corrected_code": "package org.example.app.banji;

import javax.servlet.ServletException;
import javax.servlet.annotation.WebServlet;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.io.PrintWriter;

@WebServlet("/sample018")
public class Sample018 extends HttpServlet {

    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        request.setCharacterEncoding("UTF-8");

        String op = request.getParameter("op");

        if ("search".equals(op)) {
            String banji_name = request.getParameter("banji_name");
            if (banji_name == null || banji_name.trim().isEmpty()) {
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "banji_name parameter is required");
                return;
            }
            response.setContentType("text/html;charset=UTF-8");
            try (PrintWriter out = response.getWriter()) {
                out.write("<html><body>");
                out.write("<h2>搜索结果：</h2>");
                out.write("<p>您搜索的班级名称是：" + escapeHtml(banji_name) + "</p>");
                out.write("</body></html>");
            }
        }
    }

    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        response.sendError(HttpServletResponse.SC_METHOD_NOT_ALLOWED, "GET method not supported");
    }

    private String escapeHtml(String input) {
        if (input == null) return null;
        StringBuilder escaped = new StringBuilder();
        for (char c : input.toCharArray()) {
            switch (c) {
                case '&': escaped.append("&amp;"); break;
                case '<': escaped.append("&lt;"); break;
                case '>': escaped.append("&gt;"); break;
                case '"': escaped.append("&quot;"); break;
                case '\'': escaped.append("&#x27;"); break;
                default: escaped.append(c);
            }
        }
        return escaped.toString();
    }
}"
